import React, { useEffect } from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import TokenDevelopment from "@screens/token-development-company";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const TokenDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Token Development Company", link: null },
  ];

  useEffect(() => {
    setTimeout(() => {
      window.scrollTo({
        top: "0px",
      });
    }, 100);
  }, []);
  const location = useLocation();
  const { data } = props;
  const fileUrl =
    data?.tokenDevelopmentCompanyImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org/",
    "@graph": [
      {
        "@type": "Product",
        name: "Token Development Company | Crypto Token Development",
        description:
          "Justtry Technologies develops end-to-end crypto token development services across major blockchains (Ethereum, BSC, TRON, Solana, Polygon, Avalanche, EOS). Services include token minting, listing, wallet compatibility, capped supply, pausing & burning mechanisms, and support for ERC/BEP/TRC standards.",
        url: "https://justtrytech.com/token-development-company/",
        brand: {
          "@type": "Brand",
          Name: "Justtry Technologies",
        },
        review: {
          "@type": "Review",
          reviewRating: {
            "@type": "Rating",
            ratingValue: 4.2,
            bestRating: 5,
          },
          author: {
            "@type": "Person",
            name: "danieljt",
          },
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: 4.3,
          reviewCount: 3752,
        },
      },

      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Crypto token development by Justtry Technologies enables businesses to create and deploy tokens across major blockchain networks with tailored structures and efficient management.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
          addressCountry: "IN",
        },
      },

      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "Affordable token development firms for small businesses",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Companies like Justtry Tech, CoinFactory, AppDupe, Antier, Shamla Tech, and LeewayHertz offer token services with starting costs from about $3,000–$10,000, making them suitable for startups and small projects.",
            },
          },
          {
            "@type": "Question",
            name: "What is the cost of creating a custom cryptocurrency token?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Creating a token typically costs $5,000–$50,000+, depending on complexity. Basic tokens may range from $5,000–$10,000, while advanced projects with smart contracts and apps exceed $50,000.",
            },
          },
          {
            "@type": "Question",
            name: "Top token development companies for blockchain projects",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Well-known providers include Justtry Tech, Antier, Shamla Tech, CoinFactory, AppDupe, and LeewayHertz, offering services like smart contracts, audits, tokenomics, and exchange listing support.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        image={fileUrl}
        description={validData?.description}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <TokenDevelopment db={db} />
      </main>
    </Layout_v2>
  );
};

export default TokenDevelopmentCompany;
export const queryData = graphql`
  query MyQuery {
    tokenDevelopmentCompanyImg: file(
      relativePath: { eq: "token-development-company.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "token-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
